// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.17;

enum Status {
    NULL,
    ACTIVE,
    DUE,
    CANCELLED
}

struct Subscription {
    uint256 planId;
    address subscriber;
    uint256 startTime; 
    uint256 nextChargeAt;
    uint256 billingCycle;
    Status status;
}

event Subscribed(uint256 indexed subId, address subscriber, uint256 planId);
event SubscriptionUpdated(uint256 indexed subscriptionId, Status status, address by);
event SubscriptionPaid(uint256 indexed subscriptionId, uint256 billingCycle, uint256 _nextCharge);

error InsufficientAllowance();
error SubscriptionMissing();
error SubscriptionCancelled();
error PlanNotActive();
error MerchantNotActive();
error NotSubscriber();

interface ISubscriptionManager {
    function subscribe(uint256 planId) external returns (uint256 subscriptionId);

    function confirmPayment(uint256 subscriptionId, uint256 billingCycle) external view returns (bool);

    function isChargeAllowed(uint256 subscriptionId) external view returns (bool);

    function isChargeAllowedMut(uint256 subscriptionId) external returns (bool);

    function cancel(uint256 subscriptionId) external;

    function getSubscription(uint256 subscriptionId) external view returns (Subscription memory);

    function confirmCharge(uint256 subId, uint256 cycle) external;
}

contracts/MerchantRegistry.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "./interfaces/IMerchantRegistry.sol";
import {ISubscriptionManager} from "./interfaces/ISubscriptionManager.sol";
import {IChainRegistry, UnregisteredChain} from "./interfaces/IChainRegistry.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable2Step.sol";

interface ISubscriptionsController {
    function relayMerchantProfileUpdate(
        uint256 _chain,
        address _adapter,
        bytes memory _body
    ) external;
}

contract MerchantRegistry is IMerchantRegistry, Ownable {
    IChainRegistry private immutable chainReg;
    mapping(address => Merchant) private merchants;
    mapping(bytes32 => address) private payoutAddresses;
    // Encodes the (mid, cid, token) => bool
    mapping(bytes32 => bool) private tokenAllowed;

    ISubscriptionsController public subsController;
    ISubscriptionManager public subManager;

    modifier onlyUniqueMerchants(address _mid) {
        if (merchants[_mid].active && merchants[_mid].window > 0) {
            revert MerchantNotUnique();
        }
        _;
    }
    modifier onlySubscriptionManager() {
        if (msg.sender != address(subManager)) {
            revert Unauthorized();
        }
        _;
    }

    constructor(
        address _chain,
        address _mgr,
        address _controller
    ) Ownable(msg.sender) {
        chainReg = IChainRegistry(_chain);
        subManager = ISubscriptionManager(_mgr);
        subsController = ISubscriptionsController(_controller);
    }

    function createMerchant(
        address _owner,
        uint256 _grace,
        uint256 _window,
        bytes calldata _meta
    ) external onlyUniqueMerchants(_owner) returns (address mId) {
        merchants[_owner] = Merchant({
            grace: _grace,
            window: _window,
            active: true,
            metadata: _meta
        });

        emit MerchantCreated(_owner, _meta);
        mId = _owner;
    }

    function updateMerchantConfig(
        address _mid,
        uint256 _grace,
        uint256 _window,
        bytes calldata _metadata
    ) external {
        if (msg.sender != _mid) {
            revert Unauthorized();
        }
        Merchant memory merchant = merchants[_mid];

        // Merchant must exist with the ID
        if (!merchant.active || merchant.window == 0) {
            revert MissingMerchant();
        }

        merchants[_mid] = Merchant({
            grace: _grace,
            window: _window == 0 || _window == merchant.window
                ? merchant.window
                : _window,
            active: merchant.active,
            metadata: _metadata
        });

        emit MerchantUpdated(
            _mid,
            _grace,
            _window == 0 || _window == merchant.window
                ? merchant.window
                : _window,
            _metadata
        );
    }

    function setMerchantStatus(address _mid, bool active) external {
        if (msg.sender != _mid) {
            revert Unauthorized();
        }
        Merchant storage merchant = merchants[_mid];

        // Merchant must exist with the ID
        if (merchant.window == 0) {
            revert MissingMerchant();
        }

        merchant.active = active;

        emit MerchantStatusUpdated(_mid, active);
    }

    /**
     * Updates the Merchant's payout address
     * Ideally, will send a cross-chain message to notify BillingAdapter
     *
     * This will update the payout address, if it exists
     * Subsequent charges will deal with the new _payout
     *
     * There may be a couple minutes delay (due to cross-chain messaging)
     * Charges happen on the BillingAdapter, so a cross-chain message is needed to notify
     *
     * @param _mid The merchant address
     * @param _cid The chain ID where payout is configured
     * @param _payout The address to pay to
     */
    function setPayoutAddress(
        address _mid,
        uint256 _cid,
        address _payout
    ) external {
        if (msg.sender != _mid) {
            revert Unauthorized();
        }
        // Ensure Merchant exists and is the caller of this
        Merchant memory merchant = merchants[_mid];
        if (!merchant.active || merchant.window == 0) {
            revert MissingMerchant();
        }

        // Ensure the chain is registered
        bool supported = chainReg.isChainSupported(_cid);
        if (!supported) {
            revert UnregisteredChain();
        }

        bytes32 route = keccak256(abi.encode(_mid, _cid));
        address oldAddr = payoutAddresses[route];
        payoutAddresses[route] = _payout;

        emit PayoutAddressSet(_mid, _cid, _payout, oldAddr);

        // Dispatch cross chain message
        bytes memory body = abi.encode(
            _mid,
            _cid,
            new address[](0),
            true,
            _payout
        );
        address adapter = chainReg.getBillingAdapter(_cid);
        ISubscriptionsController(subsController).relayMerchantProfileUpdate(
            _cid,
            adapter,
            body
        );
    }

    function updateAllowedToken(
        address _mid,
        uint256 _cid,
        address[] memory _tokens,
        bool _adding
    ) external {
        if (msg.sender != _mid) {
            revert Unauthorized();
        }
        Merchant storage merchant = merchants[_mid];
        if (!merchant.active || merchant.window == 0) {
            revert MissingMerchant();
        }

        require(_tokens.length > 0, "No tokens submitted!");
        for (uint i = 0; i < _tokens.length; i++) {
            // Ensure token is not already approved
            // Revert if token contains zeroAddress
            // Ensure token is supported on chain registry
            bool chainsupported = chainReg.isChainSupported(_cid);
            if (_tokens[i] == address(0) || !chainsupported) {
                revert UnsupportedChain();
            }
            bool supported = chainReg.isTokenSupported(_cid, _tokens[i]);
            if (_tokens[i] == address(0) || !supported) {
                revert UnsupportedToken();
            }

            bytes32 route = keccak256(abi.encode(_mid, _cid, _tokens[i]));
            tokenAllowed[route] = _adding ? true : false;
        }
        bytes32 payoutroute = keccak256(abi.encode(_mid, _cid));
        bytes memory body = abi.encode(
            _mid,
            _cid,
            _tokens,
            _adding,
            payoutAddresses[payoutroute]
        );
        address adapter = chainReg.getBillingAdapter(_cid);
        ISubscriptionsController(subsController).relayMerchantProfileUpdate(
            _cid,
            adapter,
            body
        );
        emit TokensAdded(_mid, _cid, _tokens, _adding);
    }

    function updateController(address _controller) external onlyOwner {
        subsController = ISubscriptionsController(_controller);
    }

    function getMerchant(address _mid) external view returns (Merchant memory) {
        return merchants[_mid];
    }

    function getPayoutAddress(
        address _mid,
        uint256 _cid
    ) external view returns (address) {
        bytes32 route = keccak256(abi.encode(_mid, _cid));

        return payoutAddresses[route];
    }

    function isApprovedToken(
        address _mid,
        uint256 _cid,
        address _token
    ) external view returns (bool) {
        Merchant memory merchant = merchants[_mid];
        if (!merchant.active || merchant.window == 0) {
            revert MissingMerchant();
        }

        // Compose the route
        bytes32 route = keccak256(abi.encode(_mid, _cid, _token));
        return tokenAllowed[route];
    }

    function setSubscriptionManager(address _mgr) external onlyOwner {
        subManager = ISubscriptionManager(_mgr);
    }
}

contracts/SubscriptionManager.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "./interfaces/ISubscriptionManager.sol";
import {Plan, IPlanRegistry} from "./interfaces/IPlanRegistry.sol";
import {Merchant, IMerchantRegistry} from "./interfaces/IMerchantRegistry.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable2Step.sol";

contract SubscriptionManager is ISubscriptionManager, Ownable {
    IMerchantRegistry private merchantReg;
    IPlanRegistry private planReg;
    address private controller;
    uint256 private nextSubId;
    mapping(uint256 => Subscription) private subscriptions;

    modifier onlyController() {
        require(msg.sender == controller, "NOT_CONTROLLER");
        _;
    }

    constructor(address _merchant, address _planReg, address _controller) Ownable(msg.sender) {
        merchantReg = IMerchantRegistry(_merchant);
        planReg = IPlanRegistry(_planReg);
        controller = _controller;
        nextSubId = 1;
    }

    /**
     * Subscribes a User to a plan ID.
     * Checks that allowance has been approved
     * Merchant must be active
     *
     * @param _pId The plan ID to subscribe to
     */
    function subscribe(uint256 _pId) external returns (uint256 _nextSubId) {
        // Check that the plan exists
        Plan memory plan = planReg.getPlan(_pId);
        if (!plan.active) {
            revert PlanNotActive();
        }

        // Merchant must exist too
        Merchant memory merchant = merchantReg.getMerchant(plan.merchantId);
        if (!merchant.active) {
            revert MerchantNotActive();
        }

        _nextSubId = nextSubId;
        // compose the Subscription
        subscriptions[_nextSubId] = Subscription({
            planId: _pId,
            subscriber: msg.sender,
            startTime: block.timestamp,
            nextChargeAt: block.timestamp + plan.interval,
            billingCycle: 1,
            status: Status.ACTIVE
        });
        nextSubId += 1;

        emit Subscribed(_nextSubId, msg.sender, _pId);
    }

    /**
     * Two approaches exist to this
     *
     * It is enough to check that the billing cycle is less that the current billing cycle.
     * When a payment is completed, that is when the billing cycle increases
     *
     * @param _subId The Id of the sub
     * @param _cycle The billing cycle to check
     *
     * @return _paid Whether the payment has happened
     */
    function confirmPayment(
        uint256 _subId,
        uint256 _cycle
    ) external view returns (bool _paid) {
        Subscription memory sub = subscriptions[_subId];
        if (
            sub.planId == 0 ||
            sub.status == Status.NULL ||
            sub.billingCycle == 0
        ) {
            revert SubscriptionMissing();
        }

        _paid = sub.billingCycle > _cycle;
    }

    /**
     * Charge is allowed if the Subscription exists,
     * If the subscription is within the window (+ grace)
     *
     * @param _subId The subscription ID
     */
    function isChargeAllowed(uint256 _subId) external view returns (bool) {
        Subscription memory sub = subscriptions[_subId];
        Plan memory plan = planReg.getPlan(sub.planId);
        Merchant memory merchant = merchantReg.getMerchant(plan.merchantId);

        uint256 grace = plan.grace > 0 ? plan.grace : merchant.grace;
        if (
            block.timestamp >= sub.nextChargeAt - merchant.window &&
            block.timestamp <= sub.nextChargeAt + grace
        ) {
            return true;
        } else {
            return false;
        }
    }

    /**
     * Charge is allowed if the Subscription exists,
     * If the subscription is within the window (+ grace)
     *
     * @param _subId The subscription ID
     */
    function isChargeAllowedMut(uint256 _subId) external returns (bool) {
        Subscription storage sub = subscriptions[_subId];
        if (
            sub.planId == 0 ||
            sub.status == Status.NULL ||
            sub.subscriber == address(0)
        ) {
            revert SubscriptionMissing();
        }

        if (sub.status == Status.CANCELLED) {
            revert SubscriptionCancelled();
        }

        Plan memory plan = planReg.getPlan(sub.planId);
        if (!plan.active) {
            revert PlanNotActive();
        }
        Merchant memory merchant = merchantReg.getMerchant(plan.merchantId);
        if (!merchant.active) {
            revert MerchantNotActive();
        }

        uint256 grace = plan.grace > 0 ? plan.grace : merchant.grace;

        if (block.timestamp > sub.nextChargeAt + grace) {
            sub.status = Status.CANCELLED;
        } else if (block.timestamp >= sub.nextChargeAt) {
            sub.status = Status.DUE;
        }

        emit SubscriptionUpdated(_subId, sub.status, msg.sender);

        uint256 window = sub.nextChargeAt > merchant.window
            ? sub.nextChargeAt - merchant.window
            : 0;

        if (
            block.timestamp >= window &&
            block.timestamp <= sub.nextChargeAt + grace
        ) {
            return true;
        } else {
            return false;
        }
    }

    function confirmCharge(
        uint256 _subId,
        uint256 _cycle
    ) external onlyController {
        // Ensure Subscription exists
        Subscription storage sub = subscriptions[_subId];
        if (sub.billingCycle == 0 || sub.planId == 0) {
            revert SubscriptionCancelled();
        }
        if (sub.status == Status.CANCELLED) {
            revert SubscriptionCancelled();
        }
        require(sub.billingCycle == _cycle, "INVALID_BILLING_CYCLE");

        Plan memory plan = planReg.getPlan(sub.planId);

        // Move the billing cycle forward
        sub.billingCycle += 1;
        sub.nextChargeAt += plan.interval;
        sub.status = Status.ACTIVE;

        emit SubscriptionPaid(_subId, sub.billingCycle, sub.nextChargeAt);
    }

    /**
     * A `User` can cancel subscription.
     * msg.sender must equal sub.subscriber
     *
     * @param _subId Subscription ID
     */
    function cancel(uint256 _subId) external {
        Subscription storage sub = subscriptions[_subId];
        if (msg.sender == sub.subscriber) {
            sub.status = Status.CANCELLED;
            emit SubscriptionUpdated(_subId, Status.CANCELLED, msg.sender);
        } else {
            revert NotSubscriber();
        }
    }

    function getSubscription(
        uint256 _subId
    ) external view returns (Subscription memory) {
        Subscription memory sub = subscriptions[_subId];
        if (
            sub.planId == 0 ||
            sub.status == Status.NULL ||
            sub.billingCycle == 0
        ) {
            revert SubscriptionMissing();
        }

        return sub;
    }

    function updateController(address _controller) external onlyOwner {
        controller = _controller;
    }

    /**
     * 
     * @param _merchant Ideally, no reasons to ever update this
     */
    function updateMerchantRegistry(address _merchant) external onlyOwner {
        merchantReg = IMerchantRegistry(_merchant);
    }

    /**
     * 
     * @param _plan Ideally, no reasons to ever update this
     */
    function updatePlanRegistry(address _plan) external onlyOwner {
        planReg = IPlanRegistry(_plan);
    }
}

